// HomeScreen's "Live posts" feed is built from real approved queue items
// (see App's approvedPosts sync effect) — a post has no per-post target in
// the schema, so every approved post uses this same confirmation goal.
const CONFIRMATION_TARGET = 50;

// Deterministic placeholder avatar for a handle — used whenever a member
// has no real photo set (no custom upload and no Instagram-derived photo
// either — see effectivePhotoURL below). Color + initials are derived from
// the handle itself so they stay consistent rather than being re-rolled
// randomly on every render.
const AVATAR_PALETTE = ["#7C6DB5", "rgba(255,107,107,0.6)", "rgba(78,204,163,0.5)", "#4D96FF", "#F4A340", "#E8618C"];
function avatarColorFor(str) {
  let hash = 0;
  for (let i=0; i<(str||"").length; i++) hash = (hash*31 + str.charCodeAt(i)) | 0;
  return AVATAR_PALETTE[Math.abs(hash) % AVATAR_PALETTE.length];
}
function initialsFromHandle(handle) {
  const clean = (handle||"").replace(/^@/,"").replace(/[._-]/g," ").trim();
  const parts = clean.split(/\s+/).filter(Boolean);
  if (parts.length===0) return "?";
  if (parts.length===1) return parts[0].slice(0,2).toUpperCase();
  return (parts[0][0]+parts[1][0]).toUpperCase();
}

// A user's display name/photo fall back to whatever their connected
// Instagram account reports (see ConnectInstagramPanel's simulated OAuth
// data — real Instagram Graph API integration is a known future step) when
// they haven't set their own. Once the user sets name/photoURL directly,
// that always wins — connecting/reconnecting Instagram never overwrites a
// personalized value.
const effectiveDisplayName = user => user?.name || user?.igConnection?.name || "";
const effectivePhotoURL = user => user?.photoURL || user?.igConnection?.profilePictureUrl || null;


