        {monthlyCommission>0 && (
          <button className="btn-dashed" style={{marginTop:10}} onClick={()=>setWalletBalance(b=>b+monthlyCommission)}>Simulate next month's payout (+€{monthlyCommission.toFixed(2)})</button>
        )}
